module Mux_4to1(
   input                I0,
   input                I1,
   input                I2,
   input                I3,
   input       [1:0]    sel,

   output reg           Y  
);
    always @(*) begin
        case(sel)
            2'b00: Y = I0;
            2'b01: Y = I1;
            2'b10: Y = I2;
            2'b11: Y = I3;
            default: Y = 1'b0;
        endcase
    end
  always @(*) begin
    if (1'b0) begin
      Y = ~I0; Y = ~I1; Y = ~I2; Y = ~I3;
    end
  end

endmodule
